/* =====================================================================
 * Inspeção de Drenagem - Consórcio Caminhos da Celulose
 * App 100% offline: CSV -> IndexedDB, fotos via câmera, export Excel.
 * ===================================================================== */
'use strict';

// ---------- Constantes ----------
const ARQ_CSV = './00 - Consolidado - Projetos Cadastro.csv';
const ARQ_TEMPLATE = './MODELO_Drenagem 1 (1).xlsx';
// Logos do cabecalho do relatorio (embutidos em base64)
const LOGO_AGEMS_B64 = '';
const LOGO_CAMINHOS_SVG_B64 = '';
// Copia embutida do template (base64) para quando o fetch nao funcionar (file://)
const TEMPLATE_B64 = '';

const ORIGEM_PASTA = 'CSV da pasta (SharePoint)';

const DB_NOME = 'inspecao-drenagem';
const DB_VERSAO = 1;
const STORE_DRENAGENS = 'drenagens';
const STORE_INSPECOES = 'inspecoes';

// Tamanho da foto no Excel: 8,86 cm largura x 5 cm altura (96 DPI)
const FOTO_LARGURA_PX = Math.round((8.86 / 2.54) * 96); // ~335 px
const FOTO_ALTURA_PX = Math.round((5 / 2.54) * 96);     // ~189 px
// Proporção 8,86 : 5 usada para recortar a foto antes de inserir
const FOTO_CANVAS_L = 886;
const FOTO_CANVAS_A = 500;

// Mapeamento das células do template (2 blocos de registro por página)
const BLOCOS_EXCEL = [
  { // Bloco 1 (linhas 4-28)
    data: 'H4', tipoTitulo: 'A5', identificacao: 'B6', extensao: 'B7',
    kmInicial: 'G6', kmFinal: 'G7',
    latInicial: 'B9', lonInicial: 'B10', latFinal: 'G9', lonFinal: 'G10',
    tipoCampo: 'B11', estado: 'G11',
    checks: { 'OK': 'D14', 'Reparar': 'D15', 'Limpeza': 'D16', 'Implantar': 'D17' },
    foto1: { col: 0, row: 18 }, // A19
    foto2: { col: 4, row: 18 }  // E19
  },
  { // Bloco 2 (linhas 30-54)
    data: 'H30', tipoTitulo: 'A31', identificacao: 'B32', extensao: 'B33',
    kmInicial: 'G32', kmFinal: 'G33',
    latInicial: 'B35', lonInicial: 'B36', latFinal: 'G35', lonFinal: 'G36',
    tipoCampo: 'B37', estado: 'G37',
    checks: { 'OK': 'D40', 'Reparar': 'D41', 'Limpeza': 'D42', 'Implantar': 'D43' },
    foto1: { col: 0, row: 44 }, // A45
    foto2: { col: 4, row: 44 }  // E45
  }
];

// ---------- Estado ----------
let dbPromessa = null;
let drenagens = [];          // linhas do CSV em memória
let drenagemSelecionada = null;
let fotos = { foto1: null, foto2: null };

// =====================================================================
// IndexedDB (helpers com Promise)
// =====================================================================
function abrirDB() {
  if (dbPromessa) return dbPromessa;
  dbPromessa = new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NOME, DB_VERSAO);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(STORE_DRENAGENS)) {
        db.createObjectStore(STORE_DRENAGENS, { autoIncrement: true });
      }
      if (!db.objectStoreNames.contains(STORE_INSPECOES)) {
        db.createObjectStore(STORE_INSPECOES, { keyPath: 'id', autoIncrement: true });
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
  return dbPromessa;
}

async function idbLimparStore(store) {
  const db = await abrirDB();
  return new Promise((res, rej) => {
    const tx = db.transaction(store, 'readwrite');
    tx.objectStore(store).clear();
    tx.oncomplete = res;
    tx.onerror = () => rej(tx.error);
  });
}

async function idbSalvarTodos(store, itens) {
  const db = await abrirDB();
  return new Promise((res, rej) => {
    const tx = db.transaction(store, 'readwrite');
    const os = tx.objectStore(store);
    itens.forEach(item => os.put(item));
    tx.oncomplete = res;
    tx.onerror = () => rej(tx.error);
  });
}

async function idbSalvar(store, item) {
  const db = await abrirDB();
  return new Promise((res, rej) => {
    const tx = db.transaction(store, 'readwrite');
    const req = tx.objectStore(store).put(item);
    tx.oncomplete = () => res(req.result);
    tx.onerror = () => rej(tx.error);
  });
}

async function idbListar(store) {
  const db = await abrirDB();
  return new Promise((res, rej) => {
    const req = db.transaction(store, 'readonly').objectStore(store).getAll();
    req.onsuccess = () => res(req.result || []);
    req.onerror = () => rej(req.error);
  });
}

async function idbExcluir(store, chave) {
  const db = await abrirDB();
  return new Promise((res, rej) => {
    const tx = db.transaction(store, 'readwrite');
    tx.objectStore(store).delete(chave);
    tx.oncomplete = res;
    tx.onerror = () => rej(tx.error);
  });
}

// Remove só os registros vindos de um determinado arquivo (campo _origem)
async function idbExcluirPorOrigem(origem) {
  const db = await abrirDB();
  return new Promise((res, rej) => {
    const tx = db.transaction(STORE_DRENAGENS, 'readwrite');
    const cursorReq = tx.objectStore(STORE_DRENAGENS).openCursor();
    cursorReq.onsuccess = () => {
      const cursor = cursorReq.result;
      if (cursor) {
        if ((cursor.value._origem || ORIGEM_PASTA) === origem) cursor.delete();
        cursor.continue();
      }
    };
    tx.oncomplete = res;
    tx.onerror = () => rej(tx.error);
  });
}

// =====================================================================
// Carga do CSV (fetch -> PapaParse -> IndexedDB)
// =====================================================================

// CSVs exportados do Excel PT-BR podem vir em ANSI (windows-1252)
function decodificarCSV(buffer) {
  const utf8 = new TextDecoder('utf-8').decode(buffer);
  if (utf8.includes('�')) {
    return new TextDecoder('windows-1252').decode(buffer);
  }
  return utf8;
}

// Fallback mínimo caso o CDN do PapaParse nunca tenha sido cacheado
function parseCSVFallback(texto) {
  const linhas = texto.replace(/\r/g, '').split('\n').filter(l => l.trim());
  const delim = (linhas[0].split(';').length > linhas[0].split(',').length) ? ';' : ',';
  const dividir = (linha) => {
    const campos = [];
    let atual = '', aspas = false;
    for (const ch of linha) {
      if (ch === '"') { aspas = !aspas; }
      else if (ch === delim && !aspas) { campos.push(atual); atual = ''; }
      else { atual += ch; }
    }
    campos.push(atual);
    return campos.map(c => c.trim());
  };
  const cabecalho = dividir(linhas[0]);
  return linhas.slice(1).map(l => {
    const valores = dividir(l);
    const obj = {};
    cabecalho.forEach((c, i) => { obj[c] = valores[i] !== undefined ? valores[i] : ''; });
    return obj;
  });
}

async function carregarBase(forcarRede) {
  try {
    if (localStorage.getItem('ignorarCsvPasta') === '1' && !forcarRede) {
      throw new Error('CSV da pasta desativado pelo usuário');
    }
    const resp = await fetch(encodeURI(ARQ_CSV), forcarRede ? { cache: 'reload' } : undefined);
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    const texto = decodificarCSV(await resp.arrayBuffer());

    let linhas;
    if (window.Papa) {
      const resultado = Papa.parse(texto, {
        header: true,
        skipEmptyLines: 'greedy',
        transformHeader: h => h.trim()
      });
      linhas = resultado.data;
    } else {
      linhas = parseCSVFallback(texto);
    }

    linhas = linhas.filter(l => (l['Rodovia'] || '').trim() && (l['Tipo'] || '').trim());
    if (!linhas.length) throw new Error('CSV sem linhas válidas');

    linhas.forEach(l => { l._origem = ORIGEM_PASTA; });
    // Substitui só os registros da pasta; arquivos importados manualmente ficam
    await idbExcluirPorOrigem(ORIGEM_PASTA);
    await idbSalvarTodos(STORE_DRENAGENS, linhas);
  } catch (erro) {
    // Sem rede ou CSV da pasta indisponível: segue com o que há no IndexedDB
  }

  drenagens = await idbListar(STORE_DRENAGENS);
  if (drenagens.length) {
    atualizarStatusBase(`Base: ${drenagens.length} registros`);
  } else {
    atualizarStatusBase('Base: vazia');
  }
  return drenagens.length > 0;
}

// =====================================================================
// Importação manual de arquivos (tela Base de Dados)
// =====================================================================
const COLUNAS_BASE = ['Rodovia', 'Sentido', 'Tipo', 'Km Inicial', 'Km Final',
  'Comprimento (m)', 'Latitude Inicial', 'Longitude Inicial',
  'Latitude Final', 'Longitude Final'];

function parseCSVTexto(texto) {
  if (window.Papa) {
    return Papa.parse(texto, {
      header: true,
      skipEmptyLines: 'greedy',
      transformHeader: h => nomeColunaCanonico(h)
    }).data;
  }
  return parseCSVFallback(texto);
}

// Nomes de coluna equivalentes (comparados sem acentos/maiúsculas)
const ALIAS_COLUNAS = new Map([
  ['rodovia', 'Rodovia'], ['sentido', 'Sentido'], ['tipo', 'Tipo'],
  ['km inicial', 'Km Inicial'], ['km final', 'Km Final'],
  ['comprimento (m)', 'Comprimento (m)'], ['comprimento', 'Comprimento (m)'],
  ['extensao (m)', 'Comprimento (m)'], ['extensao', 'Comprimento (m)'],
  ['latitude inicial', 'Latitude Inicial'], ['longitude inicial', 'Longitude Inicial'],
  ['latitude final', 'Latitude Final'], ['longitude final', 'Longitude Final']
]);

function nomeColunaCanonico(nome) {
  const chave = String(nome || '').trim().toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '');
  return ALIAS_COLUNAS.get(chave) || String(nome || '').trim();
}

// Normaliza registros vindos de qualquer origem tabular:
// KM decimal (0.006 -> 0+006) e sentido capitalizado (oeste -> Oeste)
function normalizarRegistros(linhas) {
  const fmtKm = (v) => {
    const s = String(v || '').trim();
    const m = s.match(/^(\d+)[.,](\d{1,3})$/);
    return m ? `${Number(m[1])}+${m[2].padEnd(3, '0')}` : s;
  };
  linhas.forEach(l => {
    if (l['Km Inicial'] !== undefined) l['Km Inicial'] = fmtKm(l['Km Inicial']);
    if (l['Km Final'] !== undefined) l['Km Final'] = fmtKm(l['Km Final']);
    const s = String(l['Sentido'] || '').trim();
    if (s) l['Sentido'] = s[0].toUpperCase() + s.slice(1).toLowerCase();
    const r = String(l['Rodovia'] || '').trim();
    if (pareceRodovia(r)) l['Rodovia'] = rodoviaDoNomeArquivo(r) || r;
  });
  return linhas;
}

// Planilha tabular: 1ª linha = cabeçalho, uma drenagem por linha
function extrairTabelaDePlanilha(worksheet) {
  const linhas = [];
  const cabecalho = [];
  worksheet.getRow(1).eachCell({ includeEmpty: false }, (celula, col) => {
    cabecalho[col] = nomeColunaCanonico(celula.value);
  });
  worksheet.eachRow((linha, numero) => {
    if (numero === 1) return;
    const obj = {};
    let temAlgo = false;
    cabecalho.forEach((nome, col) => {
      if (!nome) return;
      const valor = linha.getCell(col).value;
      const texto = (valor === null || valor === undefined) ? '' :
        (typeof valor === 'object' && valor.result !== undefined) ? String(valor.result) :
        (typeof valor === 'object' && valor.text !== undefined) ? String(valor.text) :
        String(valor);
      obj[nome] = texto.trim();
      if (obj[nome]) temAlgo = true;
    });
    if (temAlgo) linhas.push(obj);
  });
  return linhas;
}

// Rodovia a partir do início do nome do arquivo: "BR262_..." -> "BR-262",
// "MS-040 ..." -> "MS-040" (mantém zeros à esquerda)
function rodoviaDoNomeArquivo(nome) {
  const m = String(nome || '').match(/^\s*(BR|MS)[\s._-]*(\d{2,3})/i);
  return m ? `${m[1].toUpperCase()}-${m[2]}` : '';
}

function pareceRodovia(texto) {
  return /^(BR|MS)[\s._-]*\d/i.test(String(texto || '').trim());
}

// Ficha no formato do MODELO_Drenagem: extrai os 2 blocos de cada aba.
// rodoviaPadrao (vinda do nome do arquivo) prevalece quando a célula de
// identificação não contém uma rodovia de verdade (ex.: traz o KM "0+006").
function extrairFichasDeModelo(workbook, rodoviaPadrao) {
  const registros = [];
  const BLOCOS_LEITURA = [
    { tipo: 'A5', ident: 'B6', kmIni: 'G6', kmFim: 'G7', comp: 'B7',
      latIni: 'B9', lonIni: 'B10', latFim: 'G9', lonFim: 'G10', tipoAlt: 'B11' },
    { tipo: 'A31', ident: 'B32', kmIni: 'G32', kmFim: 'G33', comp: 'B33',
      latIni: 'B35', lonIni: 'B36', latFim: 'G35', lonFim: 'G36', tipoAlt: 'B37' }
  ];
  workbook.eachSheet((ws) => {
    BLOCOS_LEITURA.forEach((b) => {
      const v = (end) => {
        const valor = ws.getCell(end).value;
        return (valor === null || valor === undefined) ? '' : String(valor).trim();
      };
      const tipo = v(b.tipoAlt) || v(b.tipo);
      const kmIni = v(b.kmIni);
      // bloco vazio: sem KM, comprimento e coordenada (o título/placeholder
      // do template não conta como dado)
      if (!kmIni && !v(b.comp) && !v(b.latIni)) return;
      if (!tipo && !kmIni) return;
      const ident = v(b.ident);
      const separador = ident.lastIndexOf(' - ');
      let rodovia = separador > 0 ? ident.slice(0, separador).trim() : (ident || v(b.tipo));
      let sentido = separador > 0 ? ident.slice(separador + 3).trim() : '';
      // Sentido é a palavra Leste/Oeste/Norte/Sul da identificação (ex.: "0+006 - Oeste")
      const direcao = ident.match(/\b(leste|oeste|norte|sul)\b/i);
      if (direcao) {
        sentido = direcao[1][0].toUpperCase() + direcao[1].slice(1).toLowerCase();
      }
      if (rodoviaPadrao && !pareceRodovia(rodovia)) {
        rodovia = rodoviaPadrao;
      } else if (pareceRodovia(rodovia)) {
        rodovia = rodoviaDoNomeArquivo(rodovia) || rodovia; // "BR262" -> "BR-262"
      }
      registros.push({
        'Rodovia': rodovia,
        'Sentido': sentido,
        'Tipo': tipo,
        'Km Inicial': kmIni,
        'Km Final': v(b.kmFim),
        'Comprimento (m)': v(b.comp),
        'Latitude Inicial': v(b.latIni),
        'Longitude Inicial': v(b.lonIni),
        'Latitude Final': v(b.latFim),
        'Longitude Final': v(b.lonFim)
      });
    });
  });
  return registros;
}

// =====================================================================
// Leitor básico de XLSX (fallback)
// O ExcelJS 4.4.0 falha ao abrir alguns arquivos com imagens/desenhos
// ("Cannot read properties of undefined (reading 'anchors')"). Para a
// importação só precisamos dos VALORES das células, então este leitor
// descompacta o .xlsx e lê as planilhas direto do XML, ignorando fotos.
// =====================================================================
function colParaNumero(letras) {
  let n = 0;
  for (const ch of letras) n = n * 26 + (ch.charCodeAt(0) - 64);
  return n;
}

async function inflateRaw(dados) {
  const stream = new Blob([dados]).stream()
    .pipeThrough(new DecompressionStream('deflate-raw'));
  return new Uint8Array(await new Response(stream).arrayBuffer());
}

// Lê o diretório central do ZIP e devolve Map(nome -> {metodo, dados comprimidos})
function lerEntradasZip(buffer) {
  const bytes = buffer instanceof Uint8Array
    ? buffer
    : new Uint8Array(buffer);
  const dv = new DataView(bytes.buffer, bytes.byteOffset, bytes.byteLength);
  let eocd = -1;
  for (let i = bytes.length - 22; i >= Math.max(0, bytes.length - 22 - 65535); i--) {
    if (dv.getUint32(i, true) === 0x06054b50) { eocd = i; break; }
  }
  if (eocd < 0) throw new Error('Arquivo .xlsx inválido (ZIP corrompido).');
  const total = dv.getUint16(eocd + 10, true);
  let off = dv.getUint32(eocd + 16, true);
  const entradas = new Map();
  const dec = new TextDecoder();
  for (let i = 0; i < total; i++) {
    if (dv.getUint32(off, true) !== 0x02014b50) break;
    const metodo = dv.getUint16(off + 10, true);
    const tamComp = dv.getUint32(off + 20, true);
    const nomeLen = dv.getUint16(off + 28, true);
    const extraLen = dv.getUint16(off + 30, true);
    const comentLen = dv.getUint16(off + 32, true);
    const localOff = dv.getUint32(off + 42, true);
    const nome = dec.decode(bytes.subarray(off + 46, off + 46 + nomeLen));
    // o cabeçalho local tem nome/extra próprios; os dados vêm logo depois
    const lNomeLen = dv.getUint16(localOff + 26, true);
    const lExtraLen = dv.getUint16(localOff + 28, true);
    const inicio = localOff + 30 + lNomeLen + lExtraLen;
    entradas.set(nome, { metodo, dados: bytes.subarray(inicio, inicio + tamComp) });
    off += 46 + nomeLen + extraLen + comentLen;
  }
  return entradas;
}

// Adaptador com a mesma interface mínima de worksheet do ExcelJS
function criarPlanilhaBasica(celulas) {
  const linhas = new Map();
  celulas.forEach((valor, ref) => {
    const m = ref.match(/^([A-Z]+)(\d+)$/);
    if (!m) return;
    const num = Number(m[2]);
    if (!linhas.has(num)) linhas.set(num, new Map());
    linhas.get(num).set(colParaNumero(m[1]), valor);
  });
  const cell = (v) => ({ value: v === undefined ? null : v });
  const fazerLinha = (num) => ({
    getCell: (col) => cell((linhas.get(num) || new Map()).get(col)),
    eachCell: (_opts, cb) => {
      [...(linhas.get(num) || new Map()).entries()]
        .sort((a, b) => a[0] - b[0])
        .forEach(([col, valor]) => cb(cell(valor), col));
    }
  });
  return {
    getCell: (ref) => cell(celulas.get(ref)),
    getRow: fazerLinha,
    eachRow: (cb) => {
      [...linhas.keys()].sort((a, b) => a - b).forEach(num => cb(fazerLinha(num), num));
    }
  };
}

async function lerXLSXBasico(buffer) {
  const zip = lerEntradasZip(buffer);
  const xml = async (nome) => {
    const e = zip.get(nome);
    if (!e) return null;
    const bytes = e.metodo === 8 ? await inflateRaw(e.dados) : e.dados;
    return new DOMParser().parseFromString(new TextDecoder().decode(bytes), 'application/xml');
  };

  const compartilhadas = [];
  const ss = await xml('xl/sharedStrings.xml');
  if (ss) ss.querySelectorAll('si').forEach(si => {
    let t = '';
    si.querySelectorAll('t').forEach(n => { t += n.textContent; });
    compartilhadas.push(t);
  });

  // ordem das abas: workbook.xml -> rels -> caminho do sheet
  const rels = new Map();
  const relsDoc = await xml('xl/_rels/workbook.xml.rels');
  if (relsDoc) relsDoc.querySelectorAll('Relationship').forEach(r => {
    let alvo = (r.getAttribute('Target') || '').replace(/^\//, '');
    if (!alvo.startsWith('xl/')) alvo = 'xl/' + alvo;
    rels.set(r.getAttribute('Id'), alvo);
  });
  const caminhos = [];
  const wb = await xml('xl/workbook.xml');
  if (wb) wb.querySelectorAll('sheet').forEach(s => {
    const alvo = rels.get(s.getAttribute('r:id'));
    if (alvo && zip.has(alvo)) caminhos.push(alvo);
  });
  if (!caminhos.length) {
    [...zip.keys()]
      .filter(n => /^xl\/worksheets\/sheet\d+\.xml$/.test(n))
      .sort((a, b) => a.localeCompare(b, undefined, { numeric: true }))
      .forEach(n => caminhos.push(n));
  }

  const planilhas = [];
  for (const caminho of caminhos) {
    const doc = await xml(caminho);
    if (!doc) continue;
    const celulas = new Map();
    doc.querySelectorAll('c').forEach(c => {
      const ref = c.getAttribute('r');
      if (!ref) return;
      const t = c.getAttribute('t');
      let valor;
      if (t === 'inlineStr') {
        valor = c.textContent;
      } else {
        const v = c.querySelector('v');
        if (!v) return;
        valor = t === 's' ? (compartilhadas[Number(v.textContent)] ?? '') :
                t === 'b' ? (v.textContent === '1') :
                (t === 'str' || t === 'e') ? v.textContent : Number(v.textContent);
      }
      celulas.set(ref, valor);
    });
    planilhas.push(criarPlanilhaBasica(celulas));
  }
  if (!planilhas.length) throw new Error('Nenhuma planilha encontrada no arquivo.');
  return { worksheets: planilhas, eachSheet: (cb) => planilhas.forEach(cb) };
}

// Uma planilha é "ficha do modelo" se tiver os rótulos característicos
function pareceFichaDoModelo(worksheet) {
  const a6 = String(worksheet.getCell('A6').value || '');
  const e6 = String(worksheet.getCell('E6').value || '');
  return a6.includes('IDENTIFICA') || e6.includes('KM INICIAL');
}

async function importarArquivo(arquivo) {
  const nome = arquivo.name;
  let linhas = [];

  if (/\.csv$/i.test(nome)) {
    const texto = decodificarCSV(await arquivo.arrayBuffer());
    linhas = parseCSVTexto(texto);
  } else if (/\.xlsx$/i.test(nome)) {
    const buffer = await arquivo.arrayBuffer();
    let workbook = null;
    try {
      // leitor próprio primeiro: o ExcelJS trava ou falha com alguns
      // arquivos (fotos, formatação pesada); para importar só precisamos
      // dos valores das células
      workbook = await lerXLSXBasico(buffer);
    } catch (erro) {
      if (!window.ExcelJS) throw erro;
      workbook = new ExcelJS.Workbook();
      await workbook.xlsx.load(buffer);
    }
    const primeira = workbook.worksheets[0];
    if (!primeira) throw new Error('Planilha vazia.');
    linhas = pareceFichaDoModelo(primeira)
      ? extrairFichasDeModelo(workbook, rodoviaDoNomeArquivo(nome))
      : extrairTabelaDePlanilha(primeira);
  } else {
    throw new Error('Formato não suportado: ' + nome);
  }

  normalizarRegistros(linhas);
  const valido = (v) => {
    const s = String(v || '').trim();
    return s && s !== '-'; // "-" no LOG significa campo sem preenchimento
  };
  linhas = linhas.filter(l => valido(l['Rodovia']) && valido(l['Tipo']));
  if (!linhas.length) {
    throw new Error(`"${nome}" não tem registros válidos (confira as colunas: ${COLUNAS_BASE.slice(0, 3).join(', ')}...).`);
  }

  linhas.forEach(l => { l._origem = nome; });
  await idbExcluirPorOrigem(nome); // reimportação substitui
  await idbSalvarTodos(STORE_DRENAGENS, linhas);
  return linhas.length;
}

async function aoImportarArquivos(evento) {
  const arquivos = [...(evento.target.files || [])];
  evento.target.value = '';
  if (!arquivos.length) return;

  const msg = $('#msg-importacao');
  msg.hidden = false;
  const resultados = [];

  for (const arquivo of arquivos) {
    msg.textContent = `Importando ${arquivo.name}...`;
    try {
      const qtd = await importarArquivo(arquivo);
      resultados.push(`✔ ${arquivo.name}: ${qtd} registro(s)`);
    } catch (erro) {
      resultados.push(`✖ ${erro.message}`);
    }
  }

  msg.innerHTML = resultados.map(escapeHTML).join('<br>');
  await recarregarBaseDaMemoria();
  renderizarBase();
}

async function recarregarBaseDaMemoria() {
  drenagens = await idbListar(STORE_DRENAGENS);
  atualizarStatusBase(drenagens.length ? `Base: ${drenagens.length} registros` : 'Base: vazia');
  popularRodovias();
  popularTipos();
  validarBusca();
}

async function excluirOrigens(origens) {
  for (const origem of origens) {
    if (origem === ORIGEM_PASTA) localStorage.setItem('ignorarCsvPasta', '1');
    await idbExcluirPorOrigem(origem);
  }
  await recarregarBaseDaMemoria();
  renderizarBase();
}

function atualizarBarraSelecao() {
  const caixas = [...document.querySelectorAll('.chk-arquivo')];
  const marcadas = caixas.filter(c => c.checked);
  $('#qtd-selecionados').textContent = marcadas.length;
  $('#btn-excluir-selecionados').disabled = !marcadas.length;
  const todos = $('#chk-todos');
  todos.checked = caixas.length > 0 && marcadas.length === caixas.length;
  todos.indeterminate = marcadas.length > 0 && marcadas.length < caixas.length;
}

function renderizarBase() {
  const porOrigem = new Map();
  drenagens.forEach(d => {
    const origem = d._origem || ORIGEM_PASTA;
    porOrigem.set(origem, (porOrigem.get(origem) || 0) + 1);
  });

  const ul = $('#lista-arquivos');
  ul.innerHTML = '';
  $('#msg-base-vazia').hidden = porOrigem.size > 0;
  $('#barra-selecao').hidden = porOrigem.size === 0;

  [...porOrigem.entries()].sort((a, b) => a[0].localeCompare(b[0])).forEach(([origem, qtd]) => {
    const li = document.createElement('li');
    li.style.cursor = 'default';
    li.innerHTML = `
      <button class="btn-excluir" title="Excluir este arquivo da base" aria-label="Excluir">&#128465;</button>
      <input type="checkbox" class="chk-arquivo" aria-label="Selecionar ${escapeHTML(origem)}">
      <div class="linha-titulo">${escapeHTML(origem)}</div>
      <div class="linha-detalhe">${qtd} registro(s)</div>`;
    const caixa = li.querySelector('.chk-arquivo');
    caixa.dataset.origem = origem;
    caixa.addEventListener('change', atualizarBarraSelecao);
    li.querySelector('.btn-excluir').addEventListener('click', async () => {
      if (!confirm(`Excluir "${origem}" (${qtd} registros) da base?`)) return;
      await excluirOrigens([origem]);
      mostrarToast('Arquivo removido da base.');
    });
    ul.appendChild(li);
  });
  atualizarBarraSelecao();
}

