// Redimensiona a foto (economiza IndexedDB) e devolve dataURL JPEG
function processarFoto(arquivo) {
  return new Promise((resolve, reject) => {
    const url = URL.createObjectURL(arquivo);
    const img = new Image();
    img.onload = () => {
      URL.revokeObjectURL(url);
      const MAX = 1280;
      const escala = Math.min(1, MAX / Math.max(img.width, img.height));
      const canvas = document.createElement('canvas');
      canvas.width = Math.round(img.width * escala);
      canvas.height = Math.round(img.height * escala);
      canvas.getContext('2d').drawImage(img, 0, 0, canvas.width, canvas.height);
      resolve(canvas.toDataURL('image/jpeg', 0.8));
    };
    img.onerror = () => { URL.revokeObjectURL(url); reject(new Error('Falha ao ler a foto')); };
    img.src = url;
  });
}

async function aoCapturarFoto(evento, chave) {
  const arquivo = evento.target.files && evento.target.files[0];
  if (!arquivo) return;
  try {
    const dataUrl = await processarFoto(arquivo);
    fotos[chave] = dataUrl;
    const prev = $('#prev-' + chave);
    prev.src = dataUrl;
    prev.hidden = false;
  } catch (e) {
    mostrarToast('Não foi possível processar a foto.');
  }
}

async function salvarRascunho() {
  const inspetor = $('#inp-inspetor').value.trim();
  if (!inspetor) {
    mostrarToast('Informe o nome do inspetor na tela inicial.');
    return;
  }
  const radio = document.querySelector('input[name="diagnostico"]:checked');
  if (!radio) {
    mostrarToast('Selecione um diagnóstico.');
    return;
  }

  const inspecao = {
    inspetor,
    dataISO: new Date().toISOString(),
    drenagem: drenagemSelecionada,
    diagnostico: radio.value,
    foto1: fotos.foto1,
    foto2: fotos.foto2,
    observacoes: $('#inp-obs').value.trim()
  };

  try {
    await idbSalvar(STORE_INSPECOES, inspecao);
    await atualizarContadorSalvas();
    mostrarToast('Rascunho salvo com sucesso! ✔');
    await renderizarLista(); // remove a drenagem recém-inspecionada da lista
  } catch (e) {
    mostrarToast('Erro ao salvar. Espaço do dispositivo pode estar cheio.');
  }
}

// ---------- Edição de inspeção avulsa (só incluídas em campo) ----------
async function idbAtualizarDrenagemAvulsa(chaveAntiga, novo) {
  const db = await abrirDB();
  return new Promise((res, rej) => {
    const tx = db.transaction(STORE_DRENAGENS, 'readwrite');
    const req = tx.objectStore(STORE_DRENAGENS).openCursor();
    req.onsuccess = () => {
      const c = req.result;
      if (!c) return;
      const v = c.value;
      if (v && v._origem === ORIGEM_CAMPO && chaveDrenagem(v) === chaveAntiga) {
        c.update(novo);
        return;
      }
      c.continue();
    };
    tx.oncomplete = res;
    tx.onerror = () => rej(tx.error);
  });
}

async function editarInspecaoAvulsa(insp) {
  const d = insp.drenagem || {};
  const chaveAntiga = chaveDrenagem(d);
  const perguntar = (rot, atual) => {
    const r = prompt(rot, atual || '');
    return r === null ? null : r.trim();
  };
  const nvSentido = perguntar('Sentido (Leste/Oeste):', d['Sentido']);
  if (nvSentido === null) return;
  const nvKmIni = perguntar('Km Inicial (ex: 148+003):', d['Km Inicial']);
  if (nvKmIni === null) return;
  const nvKmFim = perguntar('Km Final:', d['Km Final']);
  if (nvKmFim === null) return;
  const nvComp = perguntar('Comprimento (m):', d['Comprimento (m)']);
  if (nvComp === null) return;
  const nvTipo = perguntar('Descrição (Tipo, ex: DS, DP):', d['Tipo']);
  if (nvTipo === null) return;

  d['Sentido'] = nvSentido;
  d['Km Inicial'] = nvKmIni;
  d['Km Final'] = nvKmFim;
  d['Comprimento (m)'] = nvComp;
  d['Tipo'] = nvTipo;

  await idbSalvar(STORE_INSPECOES, insp);
  const idx = drenagens.findIndex(x => (x._origem === ORIGEM_CAMPO) && chaveDrenagem(x) === chaveAntiga);
  if (idx >= 0) {
    Object.assign(drenagens[idx], d);
    try { await idbAtualizarDrenagemAvulsa(chaveAntiga, drenagens[idx]); } catch (e) {}
  }
  mostrarToast('Inspeção atualizada. ✔');
  renderizarSalvas();
}

// ---------- Tela de inspeções salvas ----------
async function renderizarSalvas() {
  const salvas = await idbListar(STORE_INSPECOES);
  const ul = $('#lista-salvas');
  ul.innerHTML = '';
  $('#msg-vazio').hidden = salvas.length > 0;
  $('#btn-gerar').disabled = salvas.length === 0;
  $('#btn-gerar-pdf').disabled = salvas.length === 0;
  $('#btn-baixar-pdf').hidden = true; // some ao reabrir a tela; volta após gerar
  $('#btn-zip').disabled = salvas.length === 0;

  salvas.sort((a, b) => (b.dataISO || '').localeCompare(a.dataISO || ''));

  // Tipos exatos que existem no CSV base. Qualquer outro Tipo => avulsa.
  const TIPOS_BASE = new Set(["Descida d'água", 'DP - CONCRETO', 'Grelha', 'Meio-Fio', 'Sarjeta']);

  salvas.forEach(insp => {
    const d = insp.drenagem || {};
    const data = insp.dataISO ? new Date(insp.dataISO).toLocaleString('pt-BR') : '';
    const tipoTxt = String(d['Tipo'] || '').trim();
    const avulsa = (d._origem === ORIGEM_CAMPO) || !TIPOS_BASE.has(tipoTxt);
    const li = document.createElement('li');
    li.style.cursor = 'default';
    li.innerHTML = `
      <button class="btn-excluir" title="Excluir" aria-label="Excluir inspeção">&#128465;</button>
      <div class="linha-titulo">
        ${avulsa ? '<button class="btn-editar-inline" title="Editar (avulsa)" aria-label="Editar">&#9998; Editar</button> ' : ''}
        ${escapeHTML(d['Rodovia'] || '?')} - ${escapeHTML(d['Tipo'] || '?')}${avulsa ? ' <span class="tag avulsa">avulsa</span>' : ''}
      </div>
      <div class="linha-detalhe">
        KM ${escapeHTML(d['Km Inicial'] || '?')} &#8594; ${escapeHTML(d['Km Final'] || '?')} &bull;
        ${escapeHTML(insp.inspetor)} &bull; ${data}
        ${insp.foto1 ? ' &bull; 📷1' : ''}${insp.foto2 ? ' 📷2' : ''}
      </div>
      <span class="tag ${insp.diagnostico.toLowerCase()}">${escapeHTML(insp.diagnostico)}</span>`;

    li.querySelector('.btn-excluir').addEventListener('click', async () => {
      if (confirm('Excluir esta inspeção?')) {
        await idbExcluir(STORE_INSPECOES, insp.id);
        await atualizarContadorSalvas();
        renderizarSalvas();
      }
    });
    const btnEd = li.querySelector('.btn-editar-inline');
    if (btnEd) btnEd.addEventListener('click', () => editarInspecaoAvulsa(insp));
    ul.appendChild(li);
  });

  mostrarTela('tela-salvas');
}

// =====================================================================
// Exportação Excel (ExcelJS + template local)
// =====================================================================

// O Service Worker mantém o template em cache, então este fetch
// funciona mesmo sem internet. Se o fetch falhar (ex.: app aberto direto
// do arquivo, sem servidor), usa a cópia embutida em TEMPLATE_B64.
async function obterTemplate() {
  try {
    const resp = await fetch(encodeURI(ARQ_TEMPLATE));
    if (!resp.ok) throw new Error('Template não encontrado (HTTP ' + resp.status + ')');
    return await resp.arrayBuffer();
  } catch (erro) {
    if (typeof TEMPLATE_B64 === 'string' && TEMPLATE_B64) {
      const bin = atob(TEMPLATE_B64);
      const bytes = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
      return bytes.buffer;
    }
    throw erro;
  }
}

// Recorta a foto na proporção exata 8,86 (L) x 5 (A) - recorte central
function recortarProporcaoExcel(dataUrl) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      const alvo = FOTO_CANVAS_L / FOTO_CANVAS_A; // 8,86 / 5
      const atual = img.width / img.height;
      let sx = 0, sy = 0, sw = img.width, sh = img.height;
      if (atual > alvo) {          // imagem mais "larga": corta laterais
        sw = img.height * alvo;
        sx = (img.width - sw) / 2;
      } else {                     // imagem mais "alta": corta topo/base
        sh = img.width / alvo;
        sy = (img.height - sh) / 2;
      }
      const canvas = document.createElement('canvas');
      canvas.width = FOTO_CANVAS_L;
      canvas.height = FOTO_CANVAS_A;
      canvas.getContext('2d').drawImage(img, sx, sy, sw, sh, 0, 0, FOTO_CANVAS_L, FOTO_CANVAS_A);
      resolve(canvas.toDataURL('image/jpeg', 0.85));
    };
    img.onerror = () => reject(new Error('Falha ao recortar foto'));
    img.src = dataUrl;
  });
}

function base64PuroDe(dataUrl) {
  return dataUrl.substring(dataUrl.indexOf(',') + 1);
}

// O template vem com fotos de exemplo nas caixas A19/E19 e A45/E45;
// elas precisam sair antes de inserirmos as fotos reais.
function removerFotosDeExemplo(worksheet) {
  if (Array.isArray(worksheet._media)) {
    worksheet._media = worksheet._media.filter(m => m.type !== 'image');
  }
}

// ---------- Logos do cabeçalho (AGEMS à esquerda, Caminhos à direita) ----------

// Converte uma posição em pixels (a partir da esquerda) no índice fracionário
// de coluna que o ExcelJS usa como âncora
function ancoraPorPixel(worksheet, alvoPx) {
  let col = 0;
  for (let c = 1; c <= 8; c++) {
    const w = ((worksheet.getColumn(c).width || 8.43) * 7) + 5;
    if (alvoPx <= w) return col + (alvoPx / w);
    alvoPx -= w;
    col++;
  }
  return col;
}

function larguraTotalPx(worksheet) {
  let total = 0;
  for (let c = 1; c <= 8; c++) total += ((worksheet.getColumn(c).width || 8.43) * 7) + 5;
  return total;
}

// Rasteriza o SVG embutido em PNG (o Excel não aceita SVG)
let logoCaminhosPngPromessa = null;
function logoCaminhosPng(alturaPx) {
  if (!logoCaminhosPngPromessa) {
    logoCaminhosPngPromessa = new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => {
        const prop = (img.naturalWidth && img.naturalHeight)
          ? img.naturalWidth / img.naturalHeight : (1764 / 602);
        const canvas = document.createElement('canvas');
        canvas.height = alturaPx * 2; // 2x para nitidez
        canvas.width = Math.round(alturaPx * 2 * prop);
        canvas.getContext('2d').drawImage(img, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/png'));
      };
      img.onerror = () => reject(new Error('Falha ao rasterizar o logo Caminhos da Celulose'));
      img.src = 'data:image/svg+xml;base64,' + LOGO_CAMINHOS_SVG_B64;
    });
  }
  return logoCaminhosPngPromessa;
}

const LOGO_ALTURA_PX = 52; // cabe nas 3 linhas vazias do topo do template

async function inserirLogos(workbook, worksheet) {
  try {
    // AGEMS (esquerda) — PNG 800x202 embutido
    const idAgems = workbook.addImage({ base64: LOGO_AGEMS_B64, extension: 'png' });
    worksheet.addImage(idAgems, {
      tl: { col: 0.05, row: 0.15 },
      ext: { width: Math.round(LOGO_ALTURA_PX * (800 / 202)), height: LOGO_ALTURA_PX },
      editAs: 'oneCell'
    });

    // Caminhos da Celulose (direita) — SVG 1764x602 rasterizado
    const png = await logoCaminhosPng(LOGO_ALTURA_PX);
    const largura = Math.round(LOGO_ALTURA_PX * (1764 / 602));
    const idCaminhos = workbook.addImage({ base64: base64PuroDe(png), extension: 'png' });
    worksheet.addImage(idCaminhos, {
      tl: { col: ancoraPorPixel(worksheet, larguraTotalPx(worksheet) - largura - 4), row: 0.15 },
      ext: { width: largura, height: LOGO_ALTURA_PX },
      editAs: 'oneCell'
    });
  } catch (erro) {
    // sem logo não é motivo para falhar o relatório
    console.warn('Logos não inseridos:', erro);
  }
}

// Limpa os textos de exemplo do bloco não utilizado (nº ímpar de inspeções)
function limparBloco(worksheet, indiceBloco) {
  const mapa = BLOCOS_EXCEL[indiceBloco];
  const enderecos = [
    mapa.data, mapa.tipoTitulo, mapa.identificacao, mapa.extensao,
    mapa.kmInicial, mapa.kmFinal, mapa.latInicial, mapa.lonInicial,
    mapa.latFinal, mapa.lonFinal, mapa.tipoCampo, mapa.estado,
    ...Object.values(mapa.checks)
  ];
  enderecos.forEach(e => { worksheet.getCell(e).value = ''; });
}

async function preencherBloco(workbook, worksheet, inspecao, indiceBloco) {
  const mapa = BLOCOS_EXCEL[indiceBloco];
  const d = inspecao.drenagem || {};
  const pegar = (col) => (d[col] !== undefined && d[col] !== null) ? String(d[col]).trim() : '';

  const definir = (endereco, valor) => { worksheet.getCell(endereco).value = valor; };

  definir(mapa.data, new Date(inspecao.dataISO).toLocaleDateString('pt-BR'));

  // Mapeamento obrigatório (Tipo exibido só como DS/DP)
  definir(mapa.tipoTitulo, classificacaoDrenagem(pegar('Tipo'))); // A5
  definir(mapa.extensao, pegar('Comprimento (m)'));        // B7
  definir(mapa.latInicial, pegar('Latitude Inicial'));     // B9
  definir(mapa.lonInicial, pegar('Longitude Inicial'));    // B10
  definir(mapa.latFinal, pegar('Latitude Final'));         // G9
  definir(mapa.lonFinal, pegar('Longitude Final'));        // G10

  // Campos complementares do layout
  definir(mapa.identificacao, `${pegar('Rodovia')} - ${pegar('Sentido')}`.replace(/ - $/, ''));
  definir(mapa.kmInicial, pegar('Km Inicial'));
  definir(mapa.kmFinal, pegar('Km Final'));
  definir(mapa.tipoCampo, classificacaoDrenagem(pegar('Tipo')));
  definir(mapa.estado, inspecao.diagnostico);

  // Checkbox "X" do diagnóstico
  const celulaCheck = mapa.checks[inspecao.diagnostico];
  if (celulaCheck) definir(celulaCheck, 'X');

  // Fotos: A19 (panorâmica) e E19 (detalhe), proporção estrita 8,86 x 5
  const inserirFoto = async (dataUrl, ancora) => {
    if (!dataUrl) return;
    const recortada = await recortarProporcaoExcel(dataUrl);
    const idImagem = workbook.addImage({
      base64: base64PuroDe(recortada),
      extension: 'jpeg'
    });
    worksheet.addImage(idImagem, {
      tl: { col: ancora.col + 0.1, row: ancora.row + 0.15 },
      ext: { width: FOTO_LARGURA_PX, height: FOTO_ALTURA_PX },
      editAs: 'oneCell'
    });
  };

  await inserirFoto(inspecao.foto1, mapa.foto1);
  await inserirFoto(inspecao.foto2, mapa.foto2);
}

let arquivoPdfPronto = null;
let urlDownloadAtual = null;

// Prepara o LINK de download (elemento <a>) com o arquivo já pronto.
// No celular, o toque direto num <a download> é o caminho mais compatível
// (o clique programático é bloqueado no modo "tela inicial"/PWA).
function prepararBotaoDownload(blob, nome, mb) {
  if (urlDownloadAtual) { try { URL.revokeObjectURL(urlDownloadAtual); } catch (e) {} }
  urlDownloadAtual = URL.createObjectURL(blob);
  arquivoPdfPronto = { blob, nome };
  const el = $('#btn-baixar-pdf');
  el.href = urlDownloadAtual;
  el.setAttribute('download', nome);
  let podeCompartilhar = false;
  try {
    podeCompartilhar = !!(navigator.canShare &&
      navigator.canShare({ files: [new File([blob], nome, { type: blob.type })] }));
  } catch (e) {}
  el.textContent = (podeCompartilhar ? '📥 Baixar / Compartilhar' : '📥 Baixar') + ` (${mb} MB)`;
  el.hidden = false;
}

function baixarArquivo(buffer, nome) {
  const blob = new Blob([buffer], {
    type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
  });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = nome;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 5000);
}

async function gerarRelatorio() {
  if (!window.ExcelJS) {
    mostrarToast('Biblioteca de Excel não carregada. Abra o app uma vez com internet.');
    return;
  }

  const btn = $('#btn-gerar');
  const msg = $('#msg-exportacao');
  btn.disabled = true;
  msg.hidden = false;

  try {
    const inspecoes = await idbListar(STORE_INSPECOES);
    if (!inspecoes.length) throw new Error('Nenhuma inspeção salva.');
    inspecoes.sort((a, b) => (a.dataISO || '').localeCompare(b.dataISO || ''));

    const template = await obterTemplate();
    const carimbo = new Date().toISOString().slice(0, 16).replace(/[:T]/g, '-');
    const totalArquivos = Math.ceil(inspecoes.length / 2);

    // O template comporta 2 inspeções por página: gera 1 arquivo a cada 2
    for (let i = 0; i < inspecoes.length; i += 2) {
      const num = (i / 2) + 1;
      msg.textContent = `Gerando arquivo ${num} de ${totalArquivos}...`;

      const workbook = new ExcelJS.Workbook();
      await workbook.xlsx.load(template.slice(0));
      const worksheet = workbook.worksheets[0];
      removerFotosDeExemplo(worksheet);
      await inserirLogos(workbook, worksheet);

      await preencherBloco(workbook, worksheet, inspecoes[i], 0);
      if (inspecoes[i + 1]) {
        await preencherBloco(workbook, worksheet, inspecoes[i + 1], 1);
      } else {
        limparBloco(worksheet, 1);
      }

      const saida = await workbook.xlsx.writeBuffer();
      const rodovia = ((inspecoes[i].drenagem || {})['Rodovia'] || 'Drenagem')
        .replace(/[^\wÀ-ú-]+/g, '_');
      baixarArquivo(saida, `Relatorio_${rodovia}_${carimbo}_${num}.xlsx`);

      // pequena pausa para o navegador não bloquear múltiplos downloads
      await new Promise(r => setTimeout(r, 600));
    }

    msg.textContent = `✔ ${totalArquivos} arquivo(s) gerado(s) com ${inspecoes.length} inspeção(ões).`;
    mostrarToast('Relatório gerado e baixado!');
  } catch (erro) {
    msg.textContent = 'Erro: ' + erro.message;
    mostrarToast('Falha ao gerar relatório: ' + erro.message, 5000);
  } finally {
    btn.disabled = false;
  }
}

// =====================================================================
// Exportação PDF (jsPDF) - mesmo layout da ficha, 2 por página,
// tudo em UM único arquivo, independente da quantidade.
// =====================================================================

// Logos em dataURL prontos para o jsPDF (reaproveita os embutidos do Excel)
async function obterLogosPdf() {
  const logos = { agems: null, caminhos: null };
  try {
    if (typeof LOGO_AGEMS_B64 === 'string' && LOGO_AGEMS_B64) {
      logos.agems = 'data:image/png;base64,' + LOGO_AGEMS_B64;
    }
  } catch (e) { /* sem logo não impede o PDF */ }
  try {
    logos.caminhos = await logoCaminhosPng(80);
  } catch (e) { /* idem */ }
  return logos;
}

// Desenha UMA ficha (meia página A4) a partir de y0. Retorna a altura usada.
async function desenharFichaPDF(doc, inspecao, y0, logos) {
  const d = inspecao.drenagem || {};
  const pegar = (c) => (d[c] !== undefined && d[c] !== null) ? String(d[c]).trim() : '';

  const X = 8;              // margem esquerda (mm)
  const W = 194;            // largura útil (A4 210 - 2x8)
  const PRETO = 0;
  let y = y0;

  const texto = (t, x, yy, opts) => doc.text(String(t || ''), x, yy, opts || {});

  // ---------- Logos ----------
  const hLogo = 9;
  if (logos.agems) {
    doc.addImage(logos.agems, 'PNG', X, y, hLogo * (800 / 202), hLogo);
  }
  if (logos.caminhos) {
    const wCam = hLogo * (1764 / 602);
    doc.addImage(logos.caminhos, 'PNG', X + W - wCam, y, wCam, hLogo);
  }
  y += hLogo + 2;

  doc.setDrawColor(PRETO);
  doc.setLineWidth(0.35);
  doc.setTextColor(PRETO);

  // ---------- Barra de título + Data ----------
  const hBarra = 7;
  const wData = 52;
  doc.setFillColor(234, 240, 235);
  doc.rect(X, y, W - wData, hBarra, 'FD');
  doc.rect(X + W - wData, y, wData, hBarra, 'S');
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  texto('MONITORAÇÃO DE DRENAGEM', X + (W - wData) / 2, y + 4.7, { align: 'center' });
  doc.setFontSize(8);
  texto('Data Insp.: ' + new Date(inspecao.dataISO).toLocaleDateString('pt-BR'),
    X + W - wData + 2, y + 4.6);
  y += hBarra;

  // ---------- Linha do Tipo (equivale à célula A5 do Excel) ----------
  const hTipo = 7;
  doc.rect(X, y, W, hTipo, 'S');
  doc.setFontSize(9.5);
  texto(classificacaoDrenagem(pegar('Tipo')), X + W / 2, y + 4.8, { align: 'center' });
  y += hTipo + 1.5;

  // ---------- Grade de campos (2 colunas de rótulo/valor) ----------
  const linhas = [
    ['IDENTIFICAÇÃO:', `${pegar('Rodovia')} - ${pegar('Sentido')}`.replace(/ - $/, ''),
     'KM INICIAL:', pegar('Km Inicial')],
    ['EXTENSÃO (m):', pegar('Comprimento (m)'), 'KM FINAL:', pegar('Km Final')],
    ['Início Coordenada X:', pegar('Latitude Inicial'), 'Fim Coordenada X:', pegar('Latitude Final')],
    ['Início Coordenada Y:', pegar('Longitude Inicial'), 'Fim Coordenada Y:', pegar('Longitude Final')],
    ['Tipo:', classificacaoDrenagem(pegar('Tipo')), 'Estado de Conservação:', inspecao.diagnostico || '']
  ];
  const hLinha = 5.8;
  const wRot = 34, wVal = (W / 2) - wRot - 2; // 2mm de respiro entre colunas
  doc.setFontSize(8);
  linhas.forEach((l) => {
    // coluna esquerda
    doc.setFont('helvetica', 'bold');
    doc.rect(X, y, wRot, hLinha, 'S');
    texto(l[0], X + 1.5, y + 3.9);
    doc.setFont('helvetica', 'normal');
    doc.rect(X + wRot, y, wVal, hLinha, 'S');
    texto(l[1], X + wRot + 1.5, y + 3.9);
    // coluna direita
    const X2 = X + W / 2 + 2;
    doc.setFont('helvetica', 'bold');
    doc.rect(X2, y, wRot, hLinha, 'S');
    texto(l[2], X2 + 1.5, y + 3.9);
    doc.setFont('helvetica', 'normal');
    doc.rect(X2 + wRot, y, wVal, hLinha, 'S');
    texto(l[3], X2 + wRot + 1.5, y + 3.9);
    y += hLinha;
  });
  y += 1.5;

  // ---------- Diagnóstico (checkboxes) ----------
  const hDiag = 7;
  doc.setFont('helvetica', 'bold');
  doc.rect(X, y, wRot, hDiag, 'S');
  texto('Diagnóstico:', X + 1.5, y + 4.6);
  doc.rect(X + wRot, y, W - wRot, hDiag, 'S');
  const opcoes = ['OK', 'Reparar', 'Limpeza', 'Implantar'];
  const passo = (W - wRot - 6) / opcoes.length;
  opcoes.forEach((op, i) => {
    const cx = X + wRot + 4 + i * passo;
    const cy = y + 1.6;
    doc.rect(cx, cy, 3.8, 3.8, 'S');
    if (inspecao.diagnostico === op) {
      texto('X', cx + 1.9, cy + 3, { align: 'center' });
    }
    doc.setFont('helvetica', 'normal');
    texto(op, cx + 5.5, cy + 3);
    doc.setFont('helvetica', 'bold');
  });
  y += hDiag + 1.5;

  // ---------- Fotos (proporção estrita 8,86 x 5) ----------
  const wFoto = (W - 3) / 2;                    // 2 caixas lado a lado
  const hCab = 5.5;
  const hFoto = (wFoto - 2) / (8.86 / 5) + 2;   // imagem interna na proporção
  const caixas = [
    { titulo: 'Foto Panorâmica', foto: inspecao.foto1, x: X },
    { titulo: 'Foto Detalhe', foto: inspecao.foto2, x: X + wFoto + 3 }
  ];
  for (const c of caixas) {
    doc.setFillColor(234, 240, 235);
    doc.rect(c.x, y, wFoto, hCab, 'FD');
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8.5);
    texto(c.titulo, c.x + wFoto / 2, y + 3.8, { align: 'center' });
    doc.rect(c.x, y + hCab, wFoto, hFoto, 'S');
    if (c.foto) {
      const recortada = await recortarProporcaoExcel(c.foto);
      doc.addImage(recortada, 'JPEG', c.x + 1, y + hCab + 1, wFoto - 2, (wFoto - 2) / (8.86 / 5));
    } else {
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(8);
      doc.setTextColor(150);
      texto('(sem foto)', c.x + wFoto / 2, y + hCab + hFoto / 2, { align: 'center' });
      doc.setTextColor(PRETO);
    }
  }
  y += hCab + hFoto;

  return y - y0; // altura total usada
}

// Monta o PDF único (2 fichas por página) e devolve { blob, nome, fichas, paginas }
async function montarPdfBlob(msg) {
  const inspecoes = await idbListar(STORE_INSPECOES);
  if (!inspecoes.length) throw new Error('Nenhuma inspeção salva.');
  inspecoes.sort((a, b) => (a.dataISO || '').localeCompare(b.dataISO || ''));

  const doc = new window.jspdf.jsPDF({ unit: 'mm', format: 'a4', compress: true });
  const logos = await obterLogosPdf();

  const Y_FICHA_1 = 8;
  const Y_FICHA_2 = 151; // metade inferior da página

  for (let i = 0; i < inspecoes.length; i++) {
    msg.textContent = `Gerando PDF: ficha ${i + 1} de ${inspecoes.length}...`;
    if (i > 0 && i % 2 === 0) doc.addPage();
    const y0 = (i % 2 === 0) ? Y_FICHA_1 : Y_FICHA_2;
    await desenharFichaPDF(doc, inspecoes[i], y0, logos);
    // devolve o controle à UI a cada ficha (importante com 100+ registros)
    await new Promise(r => setTimeout(r, 0));
  }

  const carimbo = new Date().toISOString().slice(0, 16).replace(/[:T]/g, '-');
  return {
    blob: doc.output('blob'),
    nome: `Relatorio_Drenagem_${carimbo}.pdf`,
    fichas: inspecoes.length,
    paginas: Math.ceil(inspecoes.length / 2)
  };
}

async function gerarPDF() {
  if (!(window.jspdf && window.jspdf.jsPDF)) {
    mostrarToast('Biblioteca de PDF não carregada. Abra o app uma vez com internet.');
    return;
  }

  const btn = $('#btn-gerar-pdf');
  const msg = $('#msg-exportacao');
  btn.disabled = true;
  msg.hidden = false;
  $('#btn-baixar-pdf').hidden = true;
  arquivoPdfPronto = null;

  try {
    const pdf = await montarPdfBlob(msg);
    const mb = (pdf.blob.size / 1048576).toFixed(1);
    prepararBotaoDownload(pdf.blob, pdf.nome, mb);
    msg.textContent = `✔ PDF pronto: ${pdf.fichas} ficha(s), ${pdf.paginas} página(s). Toque no botão abaixo para baixar.`;
    mostrarToast('PDF pronto! Toque no botão abaixo.');
  } catch (erro) {
    msg.textContent = 'Erro: ' + erro.message;
    mostrarToast('Falha ao gerar PDF: ' + erro.message, 5000);
  } finally {
    btn.disabled = false;
  }
}

// =====================================================================
// Exportação em ZIP: o mesmo relatório PDF único, dentro de um .zip.
// Serve como alternativa de download para celulares que travam no PDF direto.
// =====================================================================
async function gerarZIP() {
  if (!window.JSZip) {
    mostrarToast('Biblioteca de ZIP não carregada. Abra o app uma vez com internet.');
    return;
  }
  if (!(window.jspdf && window.jspdf.jsPDF)) {
    mostrarToast('Biblioteca de PDF não carregada. Abra o app uma vez com internet.');
    return;
  }
  const btn = $('#btn-zip');
  const msg = $('#msg-exportacao');
  btn.disabled = true;
  msg.hidden = false;
  $('#btn-baixar-pdf').hidden = true;
  arquivoPdfPronto = null;

  try {
    const pdf = await montarPdfBlob(msg);

    msg.textContent = 'Compactando o PDF em ZIP...';
    const zip = new JSZip();
    zip.file(pdf.nome, pdf.blob);
    const blob = await zip.generateAsync(
      { type: 'blob', compression: 'DEFLATE', compressionOptions: { level: 6 } },
      (meta) => { msg.textContent = `Compactando... ${Math.round(meta.percent)}%`; }
    );

    const nome = pdf.nome.replace(/\.pdf$/i, '.zip');
    const mb = (blob.size / 1048576).toFixed(1);
    prepararBotaoDownload(blob, nome, mb);
    msg.textContent = `✔ ZIP pronto com o PDF (${pdf.fichas} ficha(s), ${pdf.paginas} página(s)). Toque no botão abaixo para baixar.`;
    mostrarToast('ZIP pronto! Toque no botão abaixo.');
  } catch (erro) {
    msg.textContent = 'Erro: ' + erro.message;
    mostrarToast('Falha ao gerar ZIP: ' + erro.message, 5000);
  } finally {
    btn.disabled = false;
  }
}

// =====================================================================
// Inicialização
// =====================================================================
function registrarServiceWorker() {
  if (!('serviceWorker' in navigator)) return;
  navigator.serviceWorker.register('./sw.js').then(async (reg) => {
    // Sempre que abrir com internet, força buscar versão nova do SW
    try { reg.update(); } catch (e) {}
    // Quando uma nova versão do SW instalar, ativa e recarrega para o usuário
    reg.addEventListener('updatefound', () => {
      const novo = reg.installing;
      if (!novo) return;
      novo.addEventListener('statechange', () => {
        if (novo.state === 'installed' && navigator.serviceWorker.controller) {
          novo.postMessage('skipWaiting');
          mostrarToast('Atualização disponível — recarregando...', 2500);
          setTimeout(() => location.reload(), 1500);
        }
      });
    });
    // Pergunta ao SW ativo qual versão está no ar (para mostrar no rótulo)
    setTimeout(mostrarVersaoSW, 400);
  }).catch(() => {
    console.warn('Service Worker não registrado; cache offline indisponível.');
  });

  navigator.serviceWorker.addEventListener('controllerchange', () => {
    // SW novo assumiu — recarrega para pegar os arquivos atualizados
    if (!window._recarregado) { window._recarregado = true; location.reload(); }
  });
}

function mostrarVersaoSW() {
  const el = document.getElementById('status-versao');
  if (!el || !navigator.serviceWorker.controller) return;
  const canal = new MessageChannel();
  canal.port1.onmessage = (e) => {
    const v = String(e.data || '').replace('drenagem-', '');
    if (v) el.textContent = v;
  };
  try { navigator.serviceWorker.controller.postMessage('versao', [canal.port2]); } catch (e) {}
}

function ligarEventos() {
  $('#sel-rodovia').addEventListener('change', () => { popularTipos(); validarBusca(); });
  $('#sel-tipo').addEventListener('change', validarBusca);
  $('#btn-buscar').addEventListener('click', renderizarLista);
  $('#btn-incluir-nova').addEventListener('click', abrirNovaDrenagem);
  $('#btn-gps-ini').addEventListener('click', () => capturarGPS('ini'));
  $('#btn-gps-fim').addEventListener('click', () => capturarGPS('fim'));
  $('#btn-nv-continuar').addEventListener('click', continuarNovaDrenagem);
  $('#btn-ver-salvas').addEventListener('click', renderizarSalvas);
  $('#btn-gerenciar-base').addEventListener('click', () => {
    renderizarBase();
    mostrarTela('tela-base');
  });
  $('#inp-importar').addEventListener('change', aoImportarArquivos);
  $('#chk-todos').addEventListener('change', () => {
    const marcar = $('#chk-todos').checked;
    document.querySelectorAll('.chk-arquivo').forEach(c => { c.checked = marcar; });
    atualizarBarraSelecao();
  });
  $('#btn-excluir-selecionados').addEventListener('click', async () => {
    const origens = [...document.querySelectorAll('.chk-arquivo')]
      .filter(c => c.checked).map(c => c.dataset.origem);
    if (!origens.length) return;
    const qtd = drenagens.filter(d => origens.includes(d._origem || ORIGEM_PASTA)).length;
    if (!confirm(`Excluir ${origens.length} arquivo(s) (${qtd} registros) da base?`)) return;
    await excluirOrigens(origens);
    mostrarToast('Arquivos removidos da base.');
  });
  $('#btn-recarregar-pasta').addEventListener('click', async () => {
    localStorage.removeItem('ignorarCsvPasta');
    mostrarToast('Recarregando CSV da pasta...');
    await carregarBase(true);
    await recarregarBaseDaMemoria();
    renderizarBase();
  });

  // Cada foto tem 2 fontes (câmera e galeria) que gravam no mesmo slot
  $('#inp-foto1-cam').addEventListener('change', e => aoCapturarFoto(e, 'foto1'));
  $('#inp-foto1-gal').addEventListener('change', e => aoCapturarFoto(e, 'foto1'));
  $('#inp-foto2-cam').addEventListener('change', e => aoCapturarFoto(e, 'foto2'));
  $('#inp-foto2-gal').addEventListener('change', e => aoCapturarFoto(e, 'foto2'));
  $('#btn-salvar').addEventListener('click', salvarRascunho);
  $('#btn-gerar').addEventListener('click', gerarRelatorio);
  $('#btn-gerar-pdf').addEventListener('click', gerarPDF);
  $('#btn-zip').addEventListener('click', gerarZIP);
  // O elemento é um <a download>: o toque já baixa o arquivo (compatível no PWA).
  // Se o aparelho aceitar compartilhamento, usamos o menu nativo no lugar.
  $('#btn-baixar-pdf').addEventListener('click', async (e) => {
    if (!arquivoPdfPronto) return;
    const { blob, nome } = arquivoPdfPronto;
    const file = new File([blob], nome, { type: blob.type || 'application/octet-stream' });
    if (navigator.canShare && navigator.canShare({ files: [file] })) {
      e.preventDefault(); // usa o compartilhar em vez do download nativo
      try {
        await navigator.share({ files: [file], title: nome });
      } catch (err) {
        if (err && err.name !== 'AbortError') {
          mostrarToast('Compartilhar indisponível; baixando…');
          if (urlDownloadAtual) location.href = urlDownloadAtual;
        }
      }
    }
    // Se não puder compartilhar, NÃO prevenimos o padrão:
    // o próprio <a download> baixa o arquivo.
  });

  document.querySelectorAll('.btn-voltar').forEach(btn => {
    btn.addEventListener('click', () => mostrarTela(btn.dataset.voltar));
  });

  // Persiste o nome do inspetor entre sessões
  const salvo = localStorage.getItem('inspetor');
  if (salvo) $('#inp-inspetor').value = salvo;
  $('#inp-inspetor').addEventListener('input', validarBusca);
  $('#inp-inspetor').addEventListener('change', e => {
    localStorage.setItem('inspetor', e.target.value.trim());
  });

  window.addEventListener('online', atualizarStatusConexao);
  window.addEventListener('offline', atualizarStatusConexao);
}

async function iniciar() {
  registrarServiceWorker();
  ligarEventos();
  atualizarStatusConexao();
  await atualizarContadorSalvas();
  const ok = await carregarBase(false);
  if (ok) { popularRodovias(); }
}

// aguarda os scripts defer (PapaParse) estarem disponíveis
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', iniciar);
} else {
  iniciar();
}
